(66, 'EAGEAT Eaget Pen Flash Drive 3.0 128GB - Metal OTG Micro USB Type-C', 'Computing', '', 1, 7, 9500, 10, 'Color: silver stainless steel weight: 11.6 interface: startSize: 47.3 x12.3 x4.6 mmChip: UDPSystem: for Windows XP/ Vista / Win 7, Mac OS 9. X and above-read Rate: up to 30MB/S', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723469\\/imagnified\\/ilvjcigdixafbfasp0zj.jpg\"]', 20, 0, '2025-06-26 01:30:27', 1, 7600.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 10556.00, NULL, 'none', NULL, 0, 1),
(67, '10 Steps Laptop Stand', 'Home and Office', '', 18, 20, 6500, 10, 'Introducing our innovative and optimized laptop stand, designed to enhance your typing experience and provide ultimate stability. Our stand features silicone anti-slip pads that enhance friction and prevent slipping, ensuring high-frequency typing without any shaking or falling off.\r\nThe hollow heat dissipation design promotes air circulation, allowing for faster heat dissipation and creating a comfortable environment for both work and entertainment.\r\n', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723469\\/imagnified\\/izvvajuthtrjk2eubnud.jpg\"]', 25, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 7222.00, NULL, 'none', NULL, 0, 0),
(69, 'FUTURISTIC Y2K SUNGLASSES', 'Fashion', '', NULL, NULL, 9580, 10, 'Introducing the Futuristic Y2K Sunglasses - Redefining Style and Nostalgia!\r\nStep into the future while embracing the retro vibes with our cutting-edge Futuristic Y2K Sunglasses. Inspired by the iconic fashion trends of the early 2000s, these sunglasses perfectly blend vintage aesthetics with a modern twist, giving you a truly unique and stylish accessory for any occasion.\r\nDesign: Crafted with meticulous attention to detail, these sunglasses boast a sleek and futuristic design that instantly grabs attention. The frame, available in a variety of bold and vibrant colors, is made from high-quality materials that ensure durability and a comfortable fit. The futuristic shape of the lenses adds an element of intrigue, making you stand out from the crowd.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723470\\/imagnified\\/si3lp0gqqjnuxswjf3uv.jpg\"]', 0, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 10644.00, NULL, 'none', NULL, 0, 0),
(70, 'New Edition Golden Mens Sunglasses - Shades', 'Fashion', '', 5, 21, 7579, 5, 'New Edition Golden Mens Sunglasses - Shades\r\n\r\nTop Quality and Stylishly designed. Fashionable! Of High Quality!   Glasses care1. Use both hands when putting on or taking off the glasses: ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723471\\/imagnified\\/yksnbtoqeofuea6h1ild.jpg\"]', 4, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 8421.00, NULL, NULL, '[\"XS\",\"S\",\"M\",\"L\",\"XL\",\"XXL\"]', 0, 0),
