(135, 'Men Soccer Shoes High Ankle Football Boots Men Sneakerss', 'Fashion', '', 5, 12, 38842, 5, 'All our activities have sneakers. Whether you are running or exercising, we have a variety of styles to choose from.\r\nOur quality control team supervises every part of the manufacturing process. We are proud of our attention and dedication to detail design.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723557\\/imagnified\\/egav4vvdviivk2kihslz.webp\"]', 37, 1, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 43158.00, NULL, 'shoe', '[\"40\",\"41\",\"42\",\"43\",\"44\",\"45\"]', 0, 0),
(136, 'Vacuum Cleaners Cordless Home Car Portable Vacuum Sweeper', 'Home and Office', '', 18, 19, 31263, 5, 'Description:\r\nSTRONG SUCTION AND THOROUGH CLEANING --120W super power motor provides strong suction up to 4000pa, can easily absorb hair, food residue, particles, and less than 0.1 micron debris hidden in the sofa, cushion, etc. \r\nA wise choice for daily quick pick-up, car cleaning and home cleaning.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723558\\/imagnified\\/umzoyxejkniw8z6eyvmk.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723559\\/imagnified\\/jhakgd35nuvrruxzvpjr.jpg\"]', 4, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 34737.00, NULL, 'none', NULL, 0, 1),
(137, 'Glamstar 18 Inches Rechargeable Standing Fan White', 'Home and Office', '', 18, 19, 68399, 0, 'Introducing the 18-inch Rechargeable Fan with Remote (GSF-938R-B), a sophisticated and efficient cooling solution for your home or office. This sleek and modern fan boasts a generous 18-inch diameter, providing powerful airflow to keep you comfortable in any room.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723560\\/imagnified\\/kryr5cujrsr8oknkutaq.jpg\"]', 1, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 75999.00, NULL, 'none', NULL, 0, 0),
