(162, '3 Layer Wooden Dish Drainer With Cup And Cutlery Holder', 'Home and Office', '', 18, 19, 28421, 5, '2layer dish drainer rack is suitable in every kitchen in all homes, and easy to set your plate without any fear of breaking or having your dish cracked. It keeps your dish dry and ready to use. It has rubber seals at the base to protect it from getting rust. It comes with screws to help fasten each compartments when installing. Each screw also has a rubber holder that hides the screw and makes the plate rack very beautiful. It can take ceramic soup bowls, ceramic flat plates, cups, washing blows, Utensils e.t.c. It has a plastic tray underneath which receives all the drained water which will later be cleaned. ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723812\\/imagnified\\/hacgjnyl0icb0kdn1u2i.jpg\"]', 15, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 31579.00, NULL, 'none', NULL, 0, 0),
(163, '16\" Stainless Steel Dish Drainer With Cup And Cutlery Holder', 'Home and Office', '', 18, 19, 14210, 5, '2 layer dish drainer rack is suitable in every kitchen in all homes, and easy to set your plate without any fear of breaking or having your dish cracked. It keeps your dish dry and ready to us', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723813\\/imagnified\\/fiqxcanzsyce36gbxj6y.jpg\"]', 19, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 15789.00, NULL, 'none', NULL, 0, 0),
(164, 'DIY Wall Clocks 3D Mirror Stickers Large Wall Clock -Black', 'Home and Office', '', 18, 19, 5590, 5, 'Features:\r\n\r\nThe wall clock is 3D effect\r\nEasy to install and remove the sticker\r\nAlloy clock face,aluminum clock pointer and EVA foam stickers;', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723814\\/imagnified\\/kqoiwx3d00ugdw66uvfc.jpg\"]', 122, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 6211.00, NULL, 'none', NULL, 0, 0),
(165, 'High Back Ergonomic Mesh Swivel Office Chair With Headrest', 'Computing', '', 1, 7, 118421, 5, 'This contemporary computer chair features a curved mesh back that gives additional support to the lumbar area. The mid-back design offers support to the mid-to-upper back region. The mesh upholstered seat features a waterfall front edge that removes pressure from the lower legs and improves circulation', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723816\\/imagnified\\/knpkrntcefsaxbqmzjpx.jpg\"]', 12, 0, '2025-06-26 01:30:27', 1, 94736.80, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 131579.00, NULL, '', NULL, 0, 0),
(166, 'Luxury Retro Sunglasses - Anti Light Photochromic Unisex', 'Fashion', '', 5, 21, 9000, 5, 'This Golden Retro Luxury Sunglasses is a form of protective eyewear designed primarily to prevent bright light and high-energy visible light from damaging and discomforting the eyes.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723816\\/imagnified\\/xawy4f4n4wmn3aeznncj.jpg\"]', 11, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 10000.00, NULL, NULL, NULL, 0, 0),
(167, 'Splitter 7 Port USB 2.0 High Speed USB', 'Computing', '', 1, 7, 4800, 10, 'The usb interface of the desktop is usually at the back, and it is tiring to bend over to plug and unplug. Connect the USB Hub to the back, we can use the usb device directly in front of the host.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723818\\/imagnified\\/fpb4sc04zugms2xgkiiz.jpg\"]', 122, 0, '2025-06-26 01:30:27', 1, 3840.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 5333.00, NULL, 'none', NULL, 0, 0),
(168, 'Zealot S34 Portable Wireless Speaker With BT 5.0 Technology', 'Computing', '', 1, 7, 25579, 5, 'High-clear Noise Reduction: Built-in sensitive microphone, supports BT mobile phone calls, hands-free, mobile phone calls and voice chats are as clear as face-to-face.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723820\\/imagnified\\/vurx530dazq7t6hcbueq.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723821\\/imagnified\\/trrhya7wssbtozs9nmzs.jpg\"]', 12, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 28421.00, NULL, 'none', NULL, 0, 1),
(169, 'Sun King Home 200X Plus Solar Light System - Yellow', 'Home and Office', '', 18, 19, 124010, 5, 'Order the Sun King Home 200X Plus with an expandable battery. It comes with 3 tube lights, USB mobile phone charging cable plus a 15 watt solar panel. You can expand its power to charge larger appliances like TVs and fans by purchasing the solar expansion pack and battery. ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723822\\/imagnified\\/tdzgwvfonkxmbbzlwrlt.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723823\\/imagnified\\/cinpthnjt5r3ec2jdkpr.jpg\"]', 31, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 137789.00, NULL, 'none', NULL, 0, 0),
(170, 'Hp ELITEBOOK X360 1030 G3 8TH GEN CORE I5 8GB RAM/ 1TB SSD BACKLIT KEYBOARD FP READER WIN 11 PRO', 'Home and Office', '', 18, 20, 649800, 5, 'Meet the demands of your multi-task, multi-place, enterprise-business workday with the 14\" EliteBook 1030 G3 Laptop from HP is a powerful, secure, and durable system that allows teams to work from many locations.\r\n\r\n This system is powered by an 8th Gen 2.8 GHz Intel Core i5-865G7 Quad-Core processor that allows you to run multiple applications simultaneously. ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772723824\\/imagnified\\/n3rvjghyxyd4eqv8rbps.jpg\"]', 12, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 722000.00, NULL, 'none', NULL, 0, 0),
