(210, 'Oneplus Nord CE 3 5G 6.7\' 12GB RAM 256GB ROM Android 13 Dual SIM - Gray', 'Phones & Tablets', '', 4, 10, 502106, 5, 'The Nord CE3 has a 6.7-inch, 2412 x 1080 resolution AMOLED display that can refresh up to 120Hz. The display supports full coverage of the sRGB and Display P3 color spaces, 10-bit color depth, and HDR10+ certification.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772724093\\/imagnified\\/endd6jtv6tfyjo7j9zzz.jpg\"]', 100, 0, '2025-06-26 01:30:27', 1, 401684.80, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 557895.00, NULL, 'none', NULL, 0, 0),
