(429, 'Ox Giant 60 Celling Fan-copper Motor-white Colour', 'Home and Office', '', 18, 19, 83571, 30, 'It has a regulating speed of 5\r\nuniversally acceptable  \r\nDurable & fashionable\r\n230v/50hz\r\nIncredible Wind Power\r\nGorgeous Design\r\nAmazing Durability \r\nDesign to perfection', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725043\\/imagnified\\/u7loosrk0vadoydo5uan.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 92857.00, NULL, 'none', NULL, 0, 0),
(430, 'Rechargeable Fans Desktop Table Fan Colorful Led Light Fans Household Fans', 'Home and Office', '', 18, 19, 60000, 40, 'Versatile Application: The compact and space-saving design of this small cooling fan makes it suitable for a wide range of settings, including desktops, offices, cars, and camping. It offers cooling relief wherever you need it.\r\nAdjustable and Powerful: The portable table fan can be tilted 360 degrees, providing customizable airflow. It operates quietly while delivering a strong breeze, allowing for quick cooling.   With 3 different wind speeds, it caters to your specific needs.\r\nQuiet Operation: When in operation, this personal fan produces low noise levels, ensuring a peaceful environment. It keeps you cool without disturbing your work or rest, making it ideal for professional or leisurely activities.\r\nDurable Materials: Made from high-quality ABS+PP materials, the desktop fan is sturdy and long-lasting. Its durable construction ensures longevity and easy cleaning, making it a reliable choice for long-term use.\r\nMulti-functional Design: In addition to being a circulating fan, this de', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725044\\/imagnified\\/le5wwl8qsrlw8fzkpgry.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725045\\/imagnified\\/ivzwznocoirodtgmv18a.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 66667.00, NULL, 'none', NULL, 0, 0),
