(521, 'GUIXIA M10 Wireless Headset Bluetooth Earphone True Bass With Power Bank', 'Computing', '', 1, 7, 6500, 10, 'The latest Bluetooth V5.1 technology\r\n\r\nUsing CVC8.0 digital noise reduction technology\r\n\r\nHigh capacity batteries are used for a long time\r\n\r\nIPX7 waterproof and sweatproof\r\n\r\nBinaural separation design\r\n\r\nDesigned for sports\r\n\r\nMake your life different.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725198\\/imagnified\\/es7d6x7s3sdfwalnqz5n.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725199\\/imagnified\\/mx3ztfguumjylv3mmiqe.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 7222.00, NULL, 'none', NULL, 0, 0),
(522, 'Lenovo LP5 Bluetooth Headset TWS Earphones Stereo Sport', 'Computing', '', 1, 7, 28929, 30, '1. Strong signal connection stability and low latency, universal for Apple and Android phones\r\n2. Equipped with double vibrating tympanic membrane, 13mm large moving coil speaker, clear treble and deep bass\r\n3. In-ear design, better noise reduction effect\r\n4. Support voice call, binaural high-definition call, with environmental noise reduction function and clear and no noise\r\n5. The headset is touch-operated, you can switch the upper and lower music, increase and decrease the volume, answer the call and wake up the voice assistant on the headset\r\n6. Adopting life-level waterproof design, no fear of splashing from sweat and rain, and accompany you when you travel outdoors at any time', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725200\\/imagnified\\/mykehexw2h9hqytfj6hr.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725201\\/imagnified\\/lom7jooexjotw2wadfpw.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 32143.00, NULL, 'none', NULL, 0, 0),
