(613, 'MULTIFUNCTIONAL BREAKFAST MACHINE', 'Home and Office', '', 18, 19, 69999, 10, 'The  multifunctional  breakfast machine is perfect for satisfying all your breakfast needs, allowing you to make sandwiches, toast, steam eggs, fry and boil anything you want.\r\n\r\nAdjustable Temperature Control: Allows precise cooking, ensuring your food is prepared just the way you like it.\r\nTime setting: A built-in time setting helps prevent overcooking and can be set for various cooking durations.\r\nCrumb Tray: Makes cleaning up easy by collecting crumbs and spills.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725375\\/imagnified\\/qqax6olcugseab0kic1s.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 77777.00, NULL, 'none', NULL, 0, 0),
(614, 'Stainless Steel Roast Chicken Skewer Cook BBQ Grilled Fork', 'Home and Office', '', 18, 19, 19900, 10, 'Stainless Steel Roast Chicken Skewer Cook\r\n\r\n1. Material: stainless steel\r\n2. Composition: 34.2cm shaft + 2 forks + 2 screws\r\n3. Electroplating process, one-piece stamping, anti-corrosion and oil-free\r\n4. Can be adjusted according to the size of the ingredients\r\n5. Stainless steel material is not easy to deform\r\n6. Weight: 114+/-5g\r\n\r\n\r\n', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725376\\/imagnified\\/ootsvyw7qrc5bvqcxhl4.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725376\\/imagnified\\/xq5kw6581fcd7ndakdl6.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 22111.00, NULL, 'none', NULL, 0, 0),
(615, 'Multipurpose Halogen Oven And Air Fryer & Free Gift', 'Home and Office', '', 18, 19, 70000, 10, '\r\nThe multipurpose halogen oven air fryer has the ability to do Many things all from the kitchen counter top.\r\nDefrost, broil, Roast, Bake, steam, grill, and BBQ.\r\nPerfect for chicken, steak, ribs, fish, shrimp, French fries & chips and more.\r\nNo need to preheat or defrost frozen meat for the best flavor and taste.\r\nHigh temperatures & built-in fan circulates the air for moist & savory meals.\r\nWith the multipurpose halogen oven air fryer eliminates the need for any extra oil.\r\nSimply mix the food ingredients and put them into the air fryer.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725377\\/imagnified\\/rchurt0cjfeg9evl64fd.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725378\\/imagnified\\/e81ysqvgomj5jtxwh5tk.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 77778.00, NULL, 'none', NULL, 0, 0),
(616, 'Samsung Digital 28L Combination Microwave Oven With Grill', 'Home and Office', '', 18, 19, 387473, 5, 'Experience all the convenience of a microwave and oven in one as well as the flexibility of having the extra oven space, with this large capacity 28 litre Samsung MC28H5125AK. You will find the one touch healthy cooking options are simple to use and the dough proof and yoghurt making functions are sure to bring you one step closer to your homemade delights. Featuring a Smart Humidity Sensor, this innovative device monitors the moisture level of your food during the whole cooking process to ensure your meal doesnât dry out.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725379\\/imagnified\\/ugd1mqggiunccygsiixe.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 430526.00, NULL, 'none', NULL, 0, 0),
(617, 'Eurosonic Microwave Electric Oven 20L Grilliing Stainless Steel', 'Home and Office', '', 18, 19, 109125, 20, '60 mins timer with end bell signal\r\n>100Â°c-250Â°c temperature selector\r\n>3 stainless steel heating element\r\n>6 stages of switch heating selector\r\n>Indicator light\r\n>Full view window\r\n>Top Barbeque function\r\n>1300 watts', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725380\\/imagnified\\/zdv9yctu2lefoxbbfdnv.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 121250.00, NULL, 'none', NULL, 0, 0),
(618, 'Luna Family Size Standard Moonlight Digital Microwave', 'Home and Office', '', 18, 19, 165000, 10, 'The Luna microwave from Russell Hobbs has a sleek and stylish contemporary design, boasting an attractive mirror door finish. As well as an appealing look, this appliance also includes impressive functionality, with 800 watts of microwave power providing quick and convenient cooking in your home. It has a spacious cavity capacity, comfortably fitting a standard size of dinner plate. It comes with a removable and dishwasher safe glass turn-table for easy cleaning. A matching kettle and toaster are available.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725380\\/imagnified\\/yz51y4evmsvxswf1pdn8.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 183333.00, NULL, 'none', NULL, 0, 0),
(619, 'Oven Mitts And Pot Holders 4pcs Set Heat Resistant Oven', 'Home and Office', '', 18, 19, 32000, 10, 'Come with a pair of silicone oven mitts and 2 pot holders.\r\nHigh temperature resistance withstands temperatures up to 300?/572 deg;F.\r\nNon-slip silicone texture pattern helps you tighten your grip on pots, pans, and other cookware.\r\nSoft and thick padded cotton lining provides maximum heat protection and comfort.\r\nMeasures 11.8\'\' in length, long enough to protect your hands, wrists and forearms.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725381\\/imagnified\\/fagsokxotcsaahuujdb1.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725382\\/imagnified\\/sbslj8byijuifs6lt37f.jpg\"]', 100, 0, '2025-06-26 01:30:27', 1, 25600.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 35556.00, NULL, 'none', NULL, 0, 0),
