(631, 'Tower 2.2L Low Fat Air Fryer With 30 Minute Manual Timer', 'Home and Office', '', 18, 19, 70000, 10, 'Eliminate the excess fat associated with frying and create a range of delicious meals using the hot air circulation technology of the 2.2 Litre  air fryer. With only a small amount of low calorie cooking spray the enhanced airflow creates a crispy texture as it fries across a range of ingredients, including vegetables, chicken, chips and cakes. The pull out drawer requires just a simple hand wash, while the removable basket is dishwasher safe.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725395\\/imagnified\\/wpegukci3ko7maky2h3i.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725396\\/imagnified\\/c86lf0dnvtglirjzkahl.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 77778.00, NULL, 'none', NULL, 0, 0),
(632, 'Industrial Electric Deep Fryer', 'Home and Office', '', 18, 19, 125000, 10, 'Start Selling Popular Deep Fried Foods Including Chicken, Wings, Fries, Onion Rings, \r\nJalapeno Poppers, Shrimp, Fish and More! Separate Basin Tanks - Lets you Fry Two Different Foods at Two Different Temperatures!\r\nSuper Light, Weighs only 20 lbs! Perfect for Festivals, Pop-ups, Catering, Food Trucks, Carnivals, or Private \r\nFunctionsComes apart in seconds for easy cleaning, no tools necessaryReaches up to 374 Fahrenheit Temperatures', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725396\\/imagnified\\/hyz14pbte9yqay6a2faf.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 138889.00, NULL, 'none', NULL, 0, 0),
(633, '6.5 L Multi-Functional Air Fryer For- Fry-Bake-Grill-Roast', 'Home and Office', '', 18, 19, 89000, 10, 'The Electric Air Fryer 6.5L  helps you reduce up to 80% of your fat intake enabling you to fry food without the need of oil. It features rapid air technology, an adjustable temperature control and a 30 minute timer that helps you pre-set your cooking time. The Integrated air filter keeps your kitchen fresh and clean while parts of the air fryer are removable and dishwasher safe. Included is a recipe booklet to help you kick start your healthy cooking regime.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725397\\/imagnified\\/kh0hw6eh00vpfktn8ln6.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725398\\/imagnified\\/pgun095vevbqcuaawckx.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 98889.00, NULL, 'none', NULL, 0, 0),
(634, '7 In 1 Cast Iron Non Stick Masa, Omelette Pan Maker', 'Phones & Tablets', '', 18, 19, 27000, 10, '7 slots Nonstick Baking Pan. This high quality non-stick pan prevents food from sticking on to the pan, making it easy for everyone to make Masa, pan cake and much more. \r\nâ¢The pan stores heat well making the food taste delicious. The Pan has 7 molds.\r\nâ¢While the skillet comes pre-seasoned to prevent food from sticking, it works best when sprayed or lightly coated with vegetable oil before use. â¢After cooking, we recommend cleaning with a stiff nylon brush and hot water. Using soap or the dishwasher is not recommended, and harsh detergents should never be used. â¢Towel dry immediately cleaning and apply a light coating of oil to utensil while it is still warm.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725399\\/imagnified\\/m52vfmmpdpcdute7fgun.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 30000.00, NULL, 'none', NULL, 0, 1),
(635, 'Sonik Japan 3.2 Litres Airfryer With 360 Heating Rotation', 'Home and Office', '', 18, 19, 60000, 10, 'Adjustable timer.\r\nTemperature control.\r\nCapacity: 3.2L\r\nHigh-power performance for fast cooking results.\r\nEasy to clean and creates less smell than normal fryers.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725400\\/imagnified\\/n8glupnq7jky3antqjbf.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 66667.00, NULL, 'none', NULL, 0, 0),
(636, '20Litres Halogen Air Fryer Low Fat Fast Cooking Oven - 3500W', 'Home and Office', '', 18, 19, 63000, 10, 'Can be used to cook full chickens, pork and beef, baked potatoes, pizza, burgers and frozen food\r\nAdjustable temperature, ranging from 125Â° C to 250Â° C\r\nSelf-cleaning function: simply add warm soapy water\r\nTwo-year manufacturerâs warranty\r\n60-minute timer\r\nPower: 3500W\r\nCapacity: 20L\r\nMaterial glass and plastic\r\nDimensions: 41cm (H) x 34cm (L) x 33.5cm (W)', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725401\\/imagnified\\/ppyemnlblwy7lmy6kekx.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725402\\/imagnified\\/okxdofpajbvoba6bt2ol.jpg\"]', 100, 0, '2025-06-26 01:30:27', 1, 50400.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 70000.00, NULL, 'none', NULL, 0, 0),
(637, '6L Multi-functional Non-Oil Healthy Air Fryer And Oven', 'Home and Office', '', 18, 19, 73000, 10, 'The non-slip 6L Compact air fryer allows you to enjoy your favorite fried snacks and food without the added calories. Rapid air circulation technology cooks food by circulating hot air in all directions, ensuring fast and even cooking. With a temperature range of 170Â°F - 400Â°f, the fryer allows you to prepare a variety of dishes from crispy fries to juicy wings with little to no oil, and in 30 minutes or less.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725402\\/imagnified\\/eow7miyura4dbykbrxoj.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 81111.00, NULL, 'none', NULL, 0, 0),
