(644, 'Nexus 5.5kg Twin Tub Washing Machine (NX-WM-5SA)', 'Home and Office', '', 18, 19, 130000, 10, 'This Nexus NX-WM-5SA  washing machine is the ideal laundry appliance for every household. The 5.5kg capacity washer, packed full with features is not just designed to be efficient but it is also crafted to fit into your home beautifully. With its pure copper motor and rustless plastic body, this washing machine effortlessly combines style and functionality, making it both efficient and user-friendly. It also features overload protection with a buzzer & timer.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725412\\/imagnified\\/srzendrcyhtedzmf2jmt.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 144444.00, NULL, 'none', NULL, 0, 0),
(645, 'Hisense 7.5kg Twin Tub Washing Machine - (WSQB 753 (JF)', 'Home and Office', '', 18, 19, 199000, 10, 'Washing/Spinning Capacity[7.5kg]: The Hisense washing machine has a washing and spinning capacity of 7.5kg. This means that it can accommodate a maximum weight of 7.5 kilograms of laundry for both washing and spinning cycles. The capacity is suitable for medium-sized households and allows you to wash a significant amount of clothes in a single load.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725413\\/imagnified\\/chajqzx1vacx3lem87qr.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725414\\/imagnified\\/xcav5nxrfqm1idnwbchb.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 221111.00, NULL, 'none', NULL, 0, 0),
