(692, '2 In 1 Hair Straightener Curling Iron-Gold.', 'Health and Beauty', '', 3, NULL, 10000, 10, '1.Product category: roll and straight dual-use\r\n2.Applicable hair: wet and dry\r\n3.Temperature control adjustment: 1 stage\r\n4.Heat conductor material: tourmaline ceramic\r\n5.size:25*3*3cm', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725934\\/imagnified\\/lc2ojnyo44yekkvexgws.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725935\\/imagnified\\/wkishlwcyckxwutgcxgp.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 11111.00, NULL, 'none', NULL, 0, 0),
(693, 'Versatile Straight And Curly Hair Style Hot Air Comb 5 In 1', 'Health and Beauty', '', 3, NULL, 23000, 10, '5 in 1 curling wands set makes different hairstyles: The upgraded version of the curling wand set contains 5 different sizes of interchangeable with a curling brush.The versatile stylers attach to the styling wand & hair dryer and give you the power to explore styles for any hair type. The 5 in 1 hair dryer brush set includes 1x hair dryer for fast drying, 2 x 15.7 inch left & right rotating curling iron for curling, 1x hair dryer brush for volumizing, 1x hair straightener for smoothing.\r\nThe Unique Curling brush (Does Not Blow Air) is engineered longer with thermal bristles that can grab and gently glide through hair, helping to wrap the hair around the barrel for a smooth styling. Perfect for volumizing and creating loose relaxed curls and Bangs.\r\nThis hair curling iron adopts Ptc heat technology, so it can heat up in 30-sec for instant styling, saving your precious time, helps you get frizz-free & shiny curls lasting all day long.\r\nThis hair curling iron adopts Ptc heat technology, ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725936\\/imagnified\\/eaqm5qpw9smghgisx8tb.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725938\\/imagnified\\/tcbddn5msm1kbomi04wy.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 25556.00, NULL, 'none', NULL, 0, 0),
(694, 'GLOWFEEL Anti Oil Repair Solution Shampoo - Shiny And Smooth Hair Anti Broken Hair With Keratin', 'Health and Beauty', '', 3, NULL, 9473, 5, 'Prevents oily scalp and hair\r\nSmoothen and shinier hair\r\nRepair damaged hair \r\nUltimate shower relaxation experience with the scent of branded/high end perfu-me\r\nGreat smell', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725938\\/imagnified\\/giveyyc5iilvwgvy9dgg.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725939\\/imagnified\\/cridfwxfbfmph6r6l3jj.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 10526.00, NULL, 'none', NULL, 0, 0),
(695, '3 In1 Ionic Hair Dryer Curler Straightener Hair Dryer', 'Health and Beauty', '', 3, NULL, 21000, 10, 'The 3-in-1 hair dryer, styler and volumizing brush can help you create professional hairstyles in minutes, easily and quickly.\r\n3 brushes are included for different uses: curling, straightening and volumizing. \r\nThe hair dryer styler brush adopts negative ion technology, can moisturize your hair and reduce hair damage, make your hair smooth and healthy.\r\nStylish appearance, quiet operation, lightweight and portable, easy to style by yourself. Suitable for all types of hair quality.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725940\\/imagnified\\/nhrg7vowcsbd7mqj00gb.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725941\\/imagnified\\/amt6tb6ff1i18pqgxseb.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 23333.00, NULL, 'none', NULL, 0, 0),
