(698, 'NIVEA Nourishing Cocoa Body Lotion For Women - 400ml (Pack Of 2)', 'Health and Beauty', '', 3, NULL, 10000, 10, '48h nourishing deep moisture care\r\nDEEP MOISTURE SERUM and cocoa butter & vitamin E\r\nProvides moisture and smoothes away dullness\r\nLeaves skin nicely fragranced with a scent of cocoa - after just 1 application.\r\nWith Cocoa Butter', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725946\\/imagnified\\/ursz8sq21olvzpiuldec.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725946\\/imagnified\\/hqthawtjlvicpqmiablv.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 11111.00, NULL, 'none', NULL, 0, 0),
(699, 'NIVEA Perfect & Radiant 400ml Body Lotion + 50ml Roll-on', 'Health and Beauty', '', 3, NULL, 10000, 10, 'IVEA Perfect & Radiant Body Lotion is a daily moisturiser developed to enhance the skinâs natural radiance. The innovative formula of NIVEA Perfect & Radiant Body Lotion gives the desired benefits via combined effect of the active ingredients. It works through two mechanisms:\r\nEven toned skin by reducing or inhibiting overall skin pigmentation. Active ingredients added to the formula (licorice extract and Octadecenedioic acid) are known to facilitate even toned skin by acting on the melanin producing enzyme, tyrosinase.\r\nUV protection â The sunscreens added to the formula help in maintaining skin colour by protecting skin from harsh UV rays thus protecting the skin from hyperpigmentation and future skin darkening\r\n ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725947\\/imagnified\\/kvd0exw1pets51sbshse.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772725948\\/imagnified\\/w3vmt9si2jpkfdeqvxss.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 11111.00, NULL, 'none', NULL, 0, 0),
