(936, 'Hcg PREGNANCY TEST STRIP', 'Health and Beauty', '', 3, NULL, 1895, 5, 'PTEST PREGNANCY TEST kit measures a hormone called human chorionic gonadotropin (hCG) in your urine. However, these tests are qualitative, and the results are either positive or negative for pregnancy. The most sensitive test of pregnancy is best performed by a laboratory scientist , using a sample of your blood, however , PTEST has been proven to have generated a high level of reliable result while using urine . ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726413\\/imagnified\\/vd9vhbonqsh49lyw7orh.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726413\\/imagnified\\/d8zm7yp7l2uk7r40nmdh.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 2105.00, NULL, 'none', NULL, 0, 0),
(937, 'Dual Head Stethoscope + Thermometer & Gift', 'Health and Beauty', '', 3, NULL, 10000, 10, 'he stethoscope is a medical device for listening to the internal sounds of an animal or human body. It typically has a small disc-shaped resonator that is placed against the chest, and two tubes connected to earpieces. It is often used to listen to lung and heart sounds. It is also used to listen to intestines and blood flow in artries and veins In combination with a sphygomanometer it is commonly used for measurements of blood pressure.\r\n', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726414\\/imagnified\\/q9vcqxlqc1qhaahmdvve.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726415\\/imagnified\\/yrnxodj2rxylavxqadbf.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 11111.00, NULL, 'none', NULL, 0, 0),
(938, 'Portable Female Urinal Funnel Emergency Urine Funnel', 'Health and Beauty', '', 3, NULL, 5000, 10, 'Completely hygienic and easy to use.\r\nDesigned not to flow back, splash or spill.\r\nAllows women of all ages to urinate in a standing up, sitting down or lying position without undressing.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726416\\/imagnified\\/tsnmchafhnftug3f45d8.jpg\"]', 200, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 5556.00, NULL, 'none', NULL, 0, 0),
(939, 'Large Replacement Upper Arm Pressure Monitor Cuff For Adults 22', 'Health and Beauty', '', 3, NULL, 11000, 10, 'Adjustable Extra Large cuff with PVC tube, Great for adults Elderly and teenager.\r\nCompatible with almost all automatic and manual inflate pressure monitors\r\nHigh Quality and good air tightness for accurate result.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726417\\/imagnified\\/lrwesl5ly3nrhmf2bvbg.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726418\\/imagnified\\/dgiq2knxrfjtbjmly6ge.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 12222.00, NULL, 'none', NULL, 0, 0),
(940, '2000Ml Constipation Flusher Feminine Hygiene Enema Bag Sets For Colon Cleansing Silicone Hose Health Anals Vaginas Cleaner Enema Kit', 'Health and Beauty', '', 3, NULL, 37500, 10, 'Feminine Hygiene\r\nConstipation\r\nFeminine Hygiene Product\r\nConstipation Flusher\r\nColon Cleansing Silicone', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726419\\/imagnified\\/ubf0nmergliqbwgegf3s.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726420\\/imagnified\\/qhyar1yjdfknnbe4uuaz.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 41667.00, NULL, 'none', NULL, 0, 0),
(941, 'Vibroaction Vibrating Unisex Belt', 'Health and Beauty', '', 3, NULL, 30000, 10, 'Get a relaxing massage while ridding yourself from ugly cellulite-Tones and shapes your body without any exercise-Safe and inexpensive way to trim down See results in just a few days Vibroaction vibrating slimming massager belt.Vibro Action is an abdominal belt designed to help workout your abs with vibration. It can also be used to help tone other parts of the body, including your thighs, arms, and butt. If you are looking for something like this to use in the comfort and privacy of your own home', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726437\\/imagnified\\/egfxci8cy00ohznwntro.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 33333.00, NULL, 'none', NULL, 0, 0),
