(943, 'USB Rechargeable Super Ear Hearing Aid Adjustable Sound', 'Health and Beauty', '', 3, NULL, 20000, 10, 'Tips for buyers: The cause of howling/noise: The internal amplifier and the microphone are close to each other of the hearing aid, and the sound is continuously received and expanded, so it has a certain poibility of produce howling after power-on. At present, small hearing aids and high-power hearing aids on the market can hardly avoid howling, and only full-digital hearing aids can avoid howling. Ways to avoid howling/noise: 1. When the power is high (the amplified sound is large), howling is more likely to occur. Therefore, gradually increasing the volume from low can effectively avoid howling. 2. When the ear canal is completely sealed, there is no howling sound. Therefore, please use hearing aids after cleaning your ear canal, and test the earplugs from large to small to find the most suitable earplugs. 3. After the hearing aid enters the ear canal, it is recommended to push the hearing aid with your fingers and hold it for 1-2 seconds, and then release it to fully extend the earp', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726440\\/imagnified\\/wbquiwa0ftq57mstjtay.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726441\\/imagnified\\/d8l81nlmdt1aez0zgz1z.jpg\"]', 100, 0, '2025-06-26 01:30:27', 1, 16000.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 22222.00, NULL, 'none', NULL, 0, 0),
(944, 'ACON On Call Plus Glucometer Diabetes Tester Strip', 'Health and Beauty', '', 3, NULL, 15000, 10, '\r\nThe On-Call Plus Blood Glucose Test Strips make testing easy and affordable. \r\nThese Strips are to be used with On Call Plus Glucometer from On Call. \r\nThis is a packet of 25 premium strip \r\nPlease this item cannot be used if you do not yet own an On Call Glucometer\r\nSuitable for:Diabetics, seniors, pregnant', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726442\\/imagnified\\/zzh2ney7f6o06uoo7mtx.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726443\\/imagnified\\/ge8n0zs3buk4sgz4vuk0.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 16667.00, NULL, 'none', NULL, 0, 0),
(945, 'Fingertip Pulse Oximeter Mini SpO2 Monitor Oxygen', 'Health and Beauty', '', 3, NULL, 5500, 10, 'The oximeter can be used to measure oxygen saturation, pulse rate through the finger. The product is suitable for family, personal care in sports and etc.\r\n', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726444\\/imagnified\\/aughnfoeeogfw7qtc8ta.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726446\\/imagnified\\/auof7dmvvi39wtbh8ptd.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 6111.00, NULL, 'none', NULL, 0, 0),
(946, 'Cyber Sonic Hearing Aid For Children And Adult', 'Phones & Tablets', '', 1, 7, 11000, 10, 'Cyber Sonic Portable Sound Amplifier Hearing Aid brings the world to your ears.This hearing amplifiers is a great solution for those who are suffering bad hearing condition or hearing loss. Professional audiological theoretically designed with digital sound noise reduction processing, this ear device actively reduces background noise to provide great hearing experience to the maximum. With handy working mode switch button and volume control button, the user can make accurate adjustments in no time.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726447\\/imagnified\\/g8byojyonjv4z6j18l3q.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726448\\/imagnified\\/cfze9z2pu7bf5v7f55jj.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 12222.00, NULL, 'none', NULL, 0, 1),
(947, 'Digital 50KG Luggage Scale Travel Luggage Weighing Scale', 'Health and Beauty', '', 3, NULL, 9000, 10, 'Durability and Accuracy: 110lb/50kg capacity. Accuracy of up to 0.02lb/10g and 1 degree celsius\r\nBright LCD Backlit Screen: A clear LCD backlit screen for day and night visibility to accurately display both weight and temperature\r\nEasy to Use: lb/kg, Â°F/Â°C conversion units, data lock and tare functions at your fingertips\r\nTare and auto-off functions included to preserve both time and energy', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726450\\/imagnified\\/l1mpiurubrihcmijwfzq.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772726454\\/imagnified\\/ojkp85oz79qsrvllw1ww.jpg\"]', 100, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 10000.00, NULL, 'none', NULL, 0, 0),
