(1769, 'Portable Manual Blender Juice Mixer SMOOTHIE', 'Home and Office', '', 18, 19, 42000, 40, 'Smart Safety Protection System: Magnetic sensing switch ultra safe to use and clean, the juicer cup will stop working when body and bottom separated. 380ML capacity Mini blender, quit portable.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772733997\\/imagnified\\/gtase2i9clc8iupdl5lp.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772733998\\/imagnified\\/ovakidxhlku6wxcpwlyp.jpg\"]', 43, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 46667.00, NULL, 'none', NULL, 0, 0),
(1770, 'King Style 6L Stainless Steel Yam Pounder', 'Home and Office', '', 18, 19, 56700, 0, '6L yam pounder is the best and must have for every lover of yam fufu. Pounded yam is a delicious Nigerian delicacy that many enjoy but find hard to prepare due to the effort needed in its preparation. The stress of pounding with the local mortar and pestle can be really discouraging, especially after the stress of working all day. ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734011\\/imagnified\\/s2namwbksfdbzx5z4wo2.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734012\\/imagnified\\/u8odsgnw0hi6ezcmthg8.jpg\"]', 23, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 63000.00, NULL, 'none', NULL, 0, 0),
(1771, 'MR. STEEL Multipurpose Stainless Yam Pounder And Grinder 3 Liters', 'Home and Office', '', 18, 19, 30000, 10, '3L Yam Pounder - is design for pounding. It was design and produced for best output in pounding. Pounded Yam is one of the pure delicacies (devoid of any chemical/industrial processing) that every family should prepare with easy (without any hassle) and enjoy as desire. It is better when served hot.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734013\\/imagnified\\/jtgf08ur7mvecqf3ardy.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734014\\/imagnified\\/sy2yxbpmhszjmtv4tl0a.jpg\"]', 32, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 33333.00, NULL, 'none', NULL, 0, 0),
(1772, 'MR. STEEL Multipurpose Yam Pounder And Grinder 5L', 'Home and Office', '', 18, 19, 49000, 10, '5L Yam Pounder - is design for pounding. It was design and produced for best output in pounding. Pounded Yam is one of the pure delicacies (devoid of any chemical/industrial processing) that every family should prepare with easy (without any hassle) and enjoy as desire. It is better when served hot.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734014\\/imagnified\\/qjbqgjzrcanyoamgrjtg.jpg\"]', 43, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 54444.00, NULL, 'none', NULL, 0, 0),
(1773, 'German Quality Yam Pounder/food Processor 1700', 'Home and Office', '', 18, 19, 46000, 10, 'Introducing the pinnacle of efficiency and quality in kitchen appliances: the 5-liter German Quality Yam Pounder/Food Processor. Engineered with precision and German craftsmanship, this multifunctional marvel redefines convenience and performance in the culinary realm.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734015\\/imagnified\\/zmbdzwfh1lzb69ataxrx.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734016\\/imagnified\\/tvgn3j2hefd1ki3ij9br.jpg\"]', 32, 0, '2025-06-26 01:30:27', 0, NULL, NULL, NULL, 51111.00, NULL, 'none', NULL, 0, 0);
