(1882, 'Electric Hand Mixer Whisk Egg Beater Cake Baking Mixer Tool', 'Home and Office', '', 18, 19, 12000, 10, 'Features:7 speed for stir and mixing.Easy to hold with plastic handler.Eject button with safety device.Very durable and practical.Easy to use and clean.Two type stainless steel stirrer.Two types of stirrer for beating eggs, kneading dough, mixing, stirring etc. Specification:Name: Household Handheld Electric Egg BeaterFunction: beat eggs, flour, butter playPower: 180WVoltage: 220Frequency: 50/60HzPlug: EU plugWork stalls: 1-7 speed gearEgg beater placed: handheldMaterial:ABS Plastic+Stainless steelLength:18cm/7.029\' Height:13cm/5.12\' Width:7cm/2.76\'Electric Hand Mixer Whisk Egg Beater Cake Baking Mixer ToolCable length:100cm/39.4\'Package size:19x7.5x15.5cm/7.48x2.95x6.1\'Color: White+Gray', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734163\\/imagnified\\/y2nzoxjpt5w5r4v82jjs.jpg\"]', 30, 0, '2025-06-26 15:12:45', 0, NULL, NULL, NULL, 13333.00, NULL, 'none', NULL, 0, 0),
(1883, 'Apple IPhone 16 Pro Max - 8GB - 512GB -5G - Black Titanium', 'Phones & Tablets', '', 4, 9, 2100000, 20, 'Manufacturer - Apple \r\nOperating System - IOS 18\r\nRear Camera - 48MP\r\nFront Camera - 12MP\r\nRam - 8GB\r\nInternal Memory - 512GB\r\nSim Type - Nano Sim\r\nScreen Size - 6.9 Inches \r\nProcessor - Apple A18 Pro\r\n5G - Yes \r\nBattery Capacity - Li-Po 4,685 mAh', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734164\\/imagnified\\/cs7i8zaeroojflrysvez.jpg\"]', 30, 0, '2025-06-26 15:17:35', 0, NULL, NULL, NULL, 4375000.00, NULL, '', NULL, 0, 2),
(1884, 'Apple IPhone 16 - 8GB-256GB - 5G - Ultramarine', 'Phones & Tablets', '', 4, 9, 1687500, 20, 'Manufacturer - Apple \r\nOperating System - IOS 18\r\nRear Camera - 48MP\r\nFront Camera - 12MP\r\nRam - 8GB\r\nInternal Memory - 256GB\r\nSim Type -Nano Sim\r\nScreen Size - 6.1 Inches \r\nProcessor - Apple A18\r\nBattery Capacity - Li-Ion 3,651 mAh,Non Removable ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734165\\/imagnified\\/vjrpmjcibukifarticvx.jpg\"]', 40, 0, '2025-06-26 15:39:05', 0, NULL, NULL, NULL, 1875000.00, NULL, 'none', NULL, 0, 0),
(1885, 'Qasa 18 Inches AC/DC Standing Fan + Remote (Non Rechargeable)', 'Home and Office', '', 18, 19, 70000, 10, 'This Fan is a Non Rechargeable fan. it can be used as one though when you get a 12volt battery with it and a solar panel or any 12volts charger as you may require.\r\nYou do not need to depend on Public utility power to get this fan working. It is compatible or with either public utility power, solar panel, 12 volts DC power adapter or a 12 volts battery. So you can get it working with any Qasa 12v batteries or any other 12 volts batteries in the market. Very ideal in rural areas where access to power is a bit an uphill task. All you need do is get a solar to the battery to have it charged and connect the battery to the fan. With this connection, you are guaranteed of your fan 247 access to power. Do note that it is not recommended to use Solar panels bigger than 80 watts as damage could occur.\r\n\r\nQasa QSF-18R is a must for every home and office. Barbers shop, Hair salon, and anywhere cool breeze is required. It is also boxed with a remote control for great convenience to either turn on ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734166\\/imagnified\\/szw22ywfkqtnxnrkeqbq.jpg\"]', 30, 0, '2025-06-26 15:46:19', 1, 56000.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 77778.00, NULL, 'none', NULL, 0, 1),
(1886, 'Qasa 18\" AC/DC STANDING FAN -25W- NO PANEL, NO BATTERY( ENERGY SAVING ,LOW WATTAGE)', 'Home and Office', '', 18, 19, 62000, 10, 'Non-Rechargeable, LOW WATTAGE, PREPAID METER FRIENDLY\r\n\r\n \r\n\r\nDOES NOT COME WITH SOLAR GENERATOR , PANEL, OR BATTERY. THIS IS A DC/AC FAN\r\n\r\nNo need to stay in the heat when you can get a low-power consuming standing fan to get the breeze on you. Introducing the All-new Qasa QSF-18YOGA AC/DC. 18 Inches blade size Oscillatory Fan. This fan has an adjustment capability from 120cm to 145cm height. It will help with the aesthetic beauty of your room or living room. Elegant in design and taste.\r\n\r\n \r\n\r\nAerodynamic ABS blades\r\n\r\n \r\nAC /DC\r\nEfficiency motor\r\nIT DOES NOT COME WITH BATTERY , INVERTER OR PANEL\r\n25 WATTS\r\nENERGY SAVING\r\nINVERTER FRIENDLY\r\nEasy assembly base\r\nSmart storage\r\nQSF-18YOGA AC/DC\r\nStanding Fan QSF-18YOGA', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734166\\/imagnified\\/glf99thltbdmrorfevvh.jpg\"]', 30, 0, '2025-06-26 15:48:54', 1, 49600.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 68889.00, NULL, 'none', NULL, 0, 0);
