(1887, 'Standing Pedestal Fan 16 Inches Rechargeable Fan +Solar Panel + LED Light', 'Home and Office', '', 18, 19, 95000, 10, 'Solar panel charging, with the output voltage of the solar panel being 15-16V.\r\nSupports AC110-220V wide voltage input, and charging and usage are not affected at low voltages.\r\nComes with a remote control.\r\nWith LED light function, featuring two modes: high brightness and low brightness.\r\n4-speed adjustable.\r\nWith a half-hour timing function.\r\nEquipped with a USB 5V output interface for charging mobile phones, etc.\r\nBattery: 12V 4.5AH; it takes about 7 hours to fully charge via mains power.\r\nAt the highest wind speed, the discharge duration is >5 hours; at the lowest speed, it is >24 hours.\r\n16-inch fan, Solar panel  which can fully charge the battery in approximately 6 hours.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734167\\/imagnified\\/rbnd7pu8hik3rtkssdzf.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734168\\/imagnified\\/ipo1yajmgbrxiohazevu.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734169\\/imagnified\\/w6zbvw2lnlgubf5myhtd.jpg\"]', 60, 0, '2025-06-27 00:37:51', 0, NULL, NULL, NULL, 105556.00, NULL, 'none', NULL, 0, 0),
(1888, 'Solar Durable Rechargeable Standing Fan With Panel', 'Home and Office', '', 18, 19, 85000, 10, 'This rechargeable solar fan stands 16 inches tall, oscillating left and right as you wish without any disturbing noise and with moveable wheels. It runs on battery which is easy energy and with levels of air-flow speed, you can practically plan how you want it to run. No need to stay in the heat and leave the family to sweat all night till dawn. Introducing the All new blade Battery rechargeable Oscillatory Fan. This fan is capable of being used even when there is no electricity or your Generator fails to produce power. . This product comes with a 3 speed . No need to worry. We got you covered on all front.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734170\\/imagnified\\/n0mdxzjnyylpcmmll15o.jpg\"]', 55, 0, '2025-06-27 00:41:28', 0, NULL, NULL, NULL, 94444.00, NULL, 'none', NULL, 0, 0),
(1889, 'Qasa 18â Standing Fan QSF-18721 Eco + FREE SOLAR TORCH', 'Home and Office', '', 18, 19, 84375, 20, 'The **QASA 18\" Standing Fan QSF-18721 Eco** is a powerful and stylish cooling solution designed to provide optimal comfort in any space. With its large 18-inch blades, this fan delivers strong and consistent airflow, making it ideal for cooling down larger rooms, living spaces, offices, or even outdoor areas during hot days.\r\nOne of the standout features of the QSF-18721 Eco is its **adjustable height and tilting head**, allowing you to customize the direction of airflow to suit your needs. Whether you need a gentle breeze while you sleep or a strong gust to cool down a room quickly, this fan adapts easily to your preferences. The fan also features multiple speed settings, giving you complete control over the intensity of the airflow.\r\nBuilt with durability in mind, the **QASA 18\" Standing Fan** boasts a sturdy construction that ensures long-lasting performance. Its stable base prevents tipping, and the high-quality materials resist wear and tear, making it a reliable choice for daily ', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734171\\/imagnified\\/ybpfptwspbb5szesj8of.jpg\"]', 66, 0, '2025-06-27 00:45:10', 0, NULL, NULL, NULL, 93750.00, NULL, 'none', NULL, 0, 0),
(1890, 'Rechargeable 16\' Stand Fan With 2bulbs And Solar Panel', 'Home and Office', '', 18, 19, 100000, 10, 'High-Speed Rechargeable 16\" Stand Fan with 2 Bulbs and Solar Panel\r\n\r\nModel Number: SF-300A\r\nPower (W): 30W\r\nType: Air Cooling Fan\r\nMaterial: Plastic\r\nNumber of Blades: Five\r\nApplication: Hotel, Outdoor, Garage, Commercial, Household\r\nPower Source: Battery, USB, Electric, Solar\r\nControl Type: Mechanical\r\nAdjustable Height: Yes\r\nLight: 24W LED night light, 2 Bulbs\r\nInput Voltage: AC 110-240V, 50/60Hz\r\nFull Charge Time: 12-15 hours\r\nTimer: 30-minute timer\r\nSize: 16 inches\r\nSolar Panel: Available', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734172\\/imagnified\\/w1qglacbrredelgfdqmy.jpg\"]', 44, 0, '2025-06-27 00:47:35', 1, 80000.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 111111.00, NULL, 'none', NULL, 0, 1),
(1891, 'Solar And Rechargeable Standing Fan', 'Home and Office', '', 18, 19, 72000, 10, 'Enjoy cool air in your space with Nexus 18 Inch Stand Fan-NX-SF5400B. Nexus Fans are ideal for homes, offices and larger spaces. It is efficient, durable and easy to use too. The high speed motor of this fan will take care of your cooling needs making it also suitable for warehouses or large areas. The blades of Nexus Fans are rust free, thus providing optimum value for money.\r\nThe 18? standing fan features an adjustable head, and a standard 3 pin plug for convenience. It will conveniently deliver cool air . You can adjust the speed to your preference.\r\nBrowse a wide selection of top quality at Ighomall. Enjoy great deals & discounts. Nationwide Delivery.\r\n \r\n\r\n18 Inches fan\r\nStrong electric motor\r\nSingle Phase Power Supply\r\nBuilt in power cord\r\nStrong Cross Base\r\n', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734173\\/imagnified\\/cqcxlhdcbgucdvmhi2wo.jpg\"]', 55, 0, '2025-06-27 00:49:55', 0, NULL, NULL, NULL, 80000.00, NULL, 'none', NULL, 0, 0),
