(2005, 'Vaseline Cocoa Glow Body Lotion-400ml-1 Intensive Care Cocoa Glow Body Lotion-400ml', 'Health and Beauty', '', 3, NULL, 11880, 0, 'Vaseline Healthy White skin lightening body lotion is clinically proven for radiant, naturally lighter skin in as early as 2 weeks. With active system. Vitamin B3 to help bring out naturally fair skin.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734653\\/imagnified\\/yyyjlgsces9t76abhvjy.jpg\"]', 134, 1, '2025-08-26 23:46:18', 0, NULL, NULL, NULL, 13200.00, NULL, 'none', NULL, 0, 0),
