(2010, 'Harman Kardon Onyx Studio 9 â Grey - Iconic Design And Immersive Sound', 'Computing', '', 1, 7, 468948, 5, 'The Onyx Studio 9 is more than a Bluetooth speaker â itâs a statement piece that combines striking design with superb sound engineering. Its portability, smart tuning, and immersive sound make it ideal for both casual listening and special occasions. Whether youâre hosting a gathering or enjoying a quiet evening, it delivers a listening experience thatâs rich, balanced, and refined.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734660\\/imagnified\\/gaxubbayuhbtnqiemgrb.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734661\\/imagnified\\/uyhuxlm4zya8zybmvtxt.jpg\"]', 15, 0, '2025-09-08 00:11:48', 0, NULL, NULL, NULL, 521053.00, NULL, 'none', NULL, 0, 0),
(2011, 'Onyx Studio 9 Carrying/Travelling Eva Bag', 'Computing', '', 1, 7, 68000, 10, 'Premium Protection: Made of high-quality EVA material, this case offers durability and wear-resistance for long-term use, safeguarding your speaker from daily scratches and damage.\r\nPortable Design: Features a convenient handle strap, making it easy to carry during travel or outdoor activities.\r\nVersatile Carrying Options: Includes a detachable shoulder strap, allowing you to use it as a crossbody bag or shoulder bag for added convenience.\r\nCustom Fit: Specifically designed to accommodate the speaker, ensuring a snug and secure fit.\r\nTravel-Friendly: Ideal for protecting your speaker while on the go, whether for business trips or leisure activities.', 0, 'Trollz Store', 'Yes', '[\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734662\\/imagnified\\/dwljsihyj6fqewpfmaxu.jpg\",\"https:\\/\\/res.cloudinary.com\\/dg4vrra76\\/image\\/upload\\/v1772734663\\/imagnified\\/zwwja5eiy34xwtvxdney.jpg\"]', 12, 0, '2025-09-08 00:15:13', 1, 54400.00, '2026-03-06 15:32:06', '2026-03-13 15:32:06', 75556.00, NULL, 'none', NULL, 0, 1),
